-- ═══════════════════════════════════════════════════════════════════════════════
-- earthbound.lua — game module for the Archipelago BizHawk connector.
--                 EarthBound (SNES)
--
-- STATUS: REAL implementation, SOURCE-DERIVED from the official AP world
-- worlds/earthbound (Client.py, an SNIClient subclass, + Rom.py +
-- game_data/local_data.py, world_version 4.3.1). The 526-entry location table
-- was GENERATED by parsing local_data.py `check_table` with Python (not
-- hand-copied), so it is exact; signature/goal/item-delivery addresses are read
-- straight out of Client.py. Loads and runs crash-free on any ROM; self-disables
-- on a non-AP cartridge.
--
-- MEMORY MODEL (SNI → BizHawk)
-- ────────────────────────────
--   EarthBound's client is an SNIClient. SNI addresses translate to BizHawk SNES
--   memory domains exactly as the A Link to the Past module documents:
--     SNI WRAM_START(0xF50000)+off → domain "WRAM",   offset off  (= $7E0000+off)
--     SNI SRAM_START(0xE00000)+off → domain "CARTRAM" (fallback "SRAM")
--   The AP basepatch writes a 21-byte ROM name beginning "MOM2AP" at the SNES
--   internal header $00:FFC0 (Rom.py: rom.write_bytes(0x00FFC0, rom.name)). Unlike
--   ALttP — whose AP marker is mirrored into CARTRAM — EarthBound's marker lives
--   ONLY in cartridge ROM, so we read it from BizHawk's "System Bus" at 0x00FFC0
--   (the client's literal address), falling back to "CARTROM" 0xFFC0 / 0x7FC0.
--   NOTE: the snes9x NWA bridge exposes only WRAM + SRAM (no ROM region), so the
--   ROM-signature gate cannot run there — consistent with snes9x being the
--   experimental, not-yet-live-verified backend. BizHawk is the verified path.
--
-- WHAT THIS DOES (mirrors worlds/earthbound/Client.py game_watcher)
--   • poll(): the client's location scan — two flag regions:
--       WRAM 0x9C00 (0x88 bytes) for the main world (loc_id < 0xEB1000) and
--       WRAM 0xB721 (0x41 bytes) for shop slots (loc_id >= 0xEB1000); each entry
--       is {byte_offset, bit} and a check fires when byte & (1<<bit). Gated to the
--       slot's server location set, to "not on the title screen" (SAVE_FILE != 0)
--       and to "not mid-textbox" (OPEN_WINDOW == 0xFF) exactly as the client.
--   • is_goal_complete(): GAME_CLEAR (WRAM 0x9C85) bit 0 — the client's CLIENT_GOAL
--     trigger (`game_clear[0] & 0x01`).
--   • receive_item(): the client's queue-driven delivery. ITEMQUEUE_HIGH
--     (WRAM 0xB576, u16) is the count already pushed to the game; when it trails
--     the delivered stream and the game is idle (no item in flight, no cutscene),
--     the next item id (item.item-0xEB0000) is written to the right receive slot:
--       id<=0xFD            → ITEM_RECEIVED   (WRAM 0xB570)
--       id in money table   → MONEY_RECIVED   (WRAM 0xB5F1) = table index + 1
--       else (special)      → SPECIAL_RECEIVED(WRAM 0xB572) = client_specials[id]
--     The money/special tables are tiny (3 + 22 entries) and embedded verbatim.
--     items_handling here is 0b001 by default (the patched game grants its own
--     found items) or 0b111 when the slot enabled remote_items; in BOTH cases the
--     server still streams this slot's items (those from other players at minimum),
--     so the delivery path is needed and is implemented faithfully.
--
-- MODULE CONTRACT (called by bizhawk_ap_connector.lua)
--   M.init(ctx) / M.poll() -> {ids} / M.is_goal_complete() -> bool /
--   M.receive_item(item_id, meta)
-- ═══════════════════════════════════════════════════════════════════════════════

local M = {}
M.name = "earthbound"

-- Tables generated from worlds/earthbound source; ap ids are absolute (the
-- 0xEB0000 base is already baked into the keys), so detection is self-contained.
local ADDRESSES_VERIFIED = true
local WORLD_VERSION      = "4.3.1"   -- archipelago.json / local_data.world_version

-- ── Memory domains ────────────────────────────────────────────────────────────
local WRAM    = "WRAM"
local CARTRAM = "CARTRAM"     -- SNES battery SRAM in BizHawk; fallback "SRAM"

-- ── SNI-space constants (Client.py module top), as BizHawk WRAM offsets ────────
-- (already net of WRAM_START 0xF50000).
local SAVE_FILE_OFF    = 0xB4A1        -- WRAM: save slot; 0 = title screen
local OPEN_WINDOW_OFF  = 0x8958        -- WRAM: textbox-open byte; 0xFF = clear
local GAME_CLEAR_OFF   = 0x9C85        -- WRAM: goal byte (bit 0 = beat the game)
local GIYGAS_CLEAR_OFF = 0x9C11        -- WRAM: epilogue flag (bit 0 = in epilogue)
local CUR_SCENE_OFF    = 0x97B8        -- WRAM: nonzero during cutscenes
-- Location flag regions.
local LOC_MAIN_BASE    = 0x9C00        -- WRAM: main-world flags (0x88 = 136 bytes)
local LOC_SHOP_BASE    = 0xB721        -- WRAM: shop-slot flags (0x41 = 65 bytes)
-- Item delivery (Client.py receive loop).
local ITEMQUEUE_HIGH   = 0xB576        -- WRAM u16: items already pushed to the game
local ITEM_RECEIVED    = 0xB570        -- WRAM u8 : standard item id (<= 0xFD)
local SPECIAL_RECEIVED = 0xB572        -- WRAM u8 : special item routine id
local MONEY_RECIVED    = 0xB5F1        -- WRAM u8 : money item (1-based money index)

-- ROM identity: the AP basepatch writes "MOM2AP…" at the SNES header $00:FFC0.
local AP_SIG          = "MOM2AP"
local SIG_BUS_ADDR    = 0x00FFC0       -- "System Bus": client's literal address
local SIG_CARTROM_HI  = 0xFFC0         -- "CARTROM": HiROM file offset of the header
local SIG_CARTROM_LO  = 0x7FC0         -- "CARTROM": LoROM offset (last-ditch)

-- The 0xEB0000 item-id base + the money / special id remaps (Client.py +
-- local_data.py). money_id_table is keyed by the game-local id (item-0xEB0000):
--   0x114 -> $10, 0x115 -> $100, 0x116 -> $1000  → written value = (index)+1.
local ITEM_ID_BASE = 0xEB0000
local MONEY_IDS    = { 0x114, 0x115, 0x116 }     -- order = money index source
-- client_specials: game-local id (item-0xEB0000) -> SPECIAL_RECEIVED routine id.
local CLIENT_SPECIALS = {
  [0xFE]=0x01,[0xFF]=0x02,[0x100]=0x0D,[0x101]=0x03,[0x102]=0x05,[0x103]=0x0E,
  [0x104]=0x06,[0x105]=0x07,[0x106]=0x08,[0x107]=0x09,[0x108]=0x0A,[0x109]=0x0B,
  [0x10A]=0x0C,[0x10B]=0x0F,[0x10C]=0x10,[0x10D]=0x11,[0x10E]=0x12,[0x10F]=0x13,
  [0x110]=0x14,[0x111]=0x04,[0x112]=0x15,[0x113]=0x16,
}

