local items_received   = {}     -- ordered stream (extended ITEM lines)
local slot_number      = 0
local remote_items     = false  -- slot enabled full remote (0b111)
local rom_ok           = nil    -- cached "MOM2AP" signature result
local mem              = {}
local log_fn           = nil

-- main/shop flag bytes, refreshed once per poll
local main_flags = {}
local shop_flags = {}

-- ── Logging ───────────────────────────────────────────────────────────────────
local function log(msg)
  if log_fn then pcall(log_fn, "[earthbound] " .. tostring(msg)) end
end

-- ── Memory API (resolved at init; 2-arg domain form + current-domain fallback) ─
local function resolve_memory_api()
  if not memory then return false end
  mem.read_u8   = memory.read_u8     or memory.readbyte
  mem.read_u16  = memory.read_u16_le or memory.readword
  mem.write_u8  = memory.write_u8    or memory.writebyte
  mem.write_u16 = memory.write_u16_le or memory.writeword
  return mem.read_u8 ~= nil
end

local function rd(fn, addr, domain)
  if not fn then return nil end
  local ok, v = pcall(fn, addr, domain)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(fn, addr)                       -- older API: current domain
  if ok and type(v) == "number" then return v end
  return nil
end

local function read_u8(addr, domain)  return rd(mem.read_u8,  addr, domain or WRAM) end
local function read_u16(addr, domain) return rd(mem.read_u16, addr, domain or WRAM) end

local function write_u8(addr, value, domain)
  if not mem.write_u8 then return end
  if pcall(mem.write_u8, addr, value, domain or WRAM) then return end
  pcall(mem.write_u8, addr, value)
end

local function write_u16(addr, value, domain)
  if not mem.write_u16 then return end
  if pcall(mem.write_u16, addr, value, domain or WRAM) then return end
  pcall(mem.write_u16, addr, value)
end

-- Read one byte trying a list of {domain, addr} pairs in order (for the ROM sig).
local function read_first(pairs_list)
  for _, p in ipairs(pairs_list) do
    local ok, v = pcall(mem.read_u8, p[2], p[1])
    if ok and type(v) == "number" then return v, p end
  end
  return nil
end

local function bit_and(a, b)
  -- 16-bit safe AND without the bit library (cores vary).
  local res, bitval = 0, 1
  while a > 0 and b > 0 do
    if a % 2 == 1 and b % 2 == 1 then res = res + bitval end
    a = math.floor(a / 2); b = math.floor(b / 2); bitval = bitval * 2
  end
  return res
end

local POW2 = { [0]=1, 2, 4, 8, 16, 32, 64, 128 }

-- ── ROM identity: the AP basepatch writes "MOM2AP" at the SNES header $00:FFC0 ─
-- Tries "System Bus" 0x00FFC0 (the client's literal address) first, then CARTROM
-- HiROM/LoROM header offsets. Whichever domain yields "MOM2AP" is cached.
local function rom_is_ap()
  if rom_ok ~= nil then return rom_ok end
  -- Pick the domain/base that returns the first signature byte, then verify all 6.
  local first, picked = read_first({
    { "System Bus", SIG_BUS_ADDR },
    { "CARTROM",    SIG_CARTROM_HI },
    { "CARTROM",    SIG_CARTROM_LO },
    { "ROM",        SIG_CARTROM_HI },
  })
  if first == nil then return false end           -- ROM not readable yet; retry
  if first ~= string.byte(AP_SIG, 1) then
    rom_ok = false
    log("non-AP ROM (no 'MOM2AP' signature) — detection idle, no writes")
    return false
  end
  for i = 2, #AP_SIG do
    local ok, b = pcall(mem.read_u8, picked[2] + i - 1, picked[1])
    if not ok or type(b) ~= "number" then return false end
    if b ~= string.byte(AP_SIG, i) then
      rom_ok = false
      log("non-AP ROM (no 'MOM2AP' signature) — detection idle, no writes")
      return false
    end
  end
  rom_ok = true
  log(("AP ROM verified ('MOM2AP' present via %s 0x%X)"):format(picked[1], picked[2]))
  return true
end

-- ── Multiworld context ────────────────────────────────────────────────────────
local function load_locations(ids)
  if type(ids) ~= "table" then return end
  server_locations = {}
  local n = 0
  for _, id in ipairs(ids) do
    local v = tonumber(id)
    if v then server_locations[v] = true; n = n + 1 end
  end
  log("server location set: " .. n .. " ids")
end

local function wanted(ap_id)
  if server_locations == nil then return true end   -- no set provided → report all
  return server_locations[ap_id] == true
end

-- Item-stream filter, same policy as the ALttP module: in the default 0b001 mode
-- the patched game grants its own found items, so own-world items are dropped
-- unless the slot is in full remote mode; server/starting entries are dropped.
local function accept_item(it)
  if it.player == nil then return true end          -- legacy ITEM:<id> line
  if it.player == 0 and (it.location or 0) <= 0 then return false end
  if (not remote_items) and it.player == slot_number then return false end
  return true
end

local function delivery_list()
  local out = {}
  for _, it in ipairs(items_received) do
    if accept_item(it) then out[#out + 1] = it end
  end
  return out
end

-- ── Detection gates (Client.py game_watcher) ──────────────────────────────────
-- title screen: SAVE_FILE == 0; epilogue: GIYGAS_CLEAR bit 0 set.
local function in_gameplay()
  local save = read_u8(SAVE_FILE_OFF)
  if save == nil or save == 0 then return false end
  local epi = read_u8(GIYGAS_CLEAR_OFF)
  if epi ~= nil and bit_and(epi, 0x01) ~= 0 then return false end
  return true
end

-- textbox gate: the client only commits checks when OPEN_WINDOW == 0xFF.
local function textbox_clear()
  local w = read_u8(OPEN_WINDOW_OFF)
  return w ~= nil and w == 0xFF
end

local function refresh_flags()
  for i = 0, 0x87 do main_flags[i] = read_u8(LOC_MAIN_BASE + i) end
  for i = 0, 0x40 do shop_flags[i] = read_u8(LOC_SHOP_BASE + i) end
end

local function flag_set(region, off, bit)
  local b = region[off]
  if b == nil then return false end
  return bit_and(b, POW2[bit]) ~= 0
end

local function scan_into(new)
  for ap_id, e in pairs(LOC_MAIN) do
    if not reported[ap_id] and wanted(ap_id) and flag_set(main_flags, e[1], e[2]) then
      reported[ap_id] = true; new[#new + 1] = ap_id
    end
  end
  for ap_id, e in pairs(LOC_SHOP) do
    if not reported[ap_id] and wanted(ap_id) and flag_set(shop_flags, e[1], e[2]) then
      reported[ap_id] = true; new[#new + 1] = ap_id
    end
  end
end

-- ── Module contract ───────────────────────────────────────────────────────────

function M.init(ctx)
  if ctx and type(ctx.log) == "function" then log_fn = ctx.log end
  if not resolve_memory_api() then
    log("BizHawk memory API unavailable — module idle")
    ADDRESSES_VERIFIED = false
    return
  end
  local cfg = (ctx and ctx.config) or {}
  slot_number = tonumber(cfg.slot_number) or 0
  local sd = cfg.slot_data
  if type(sd) == "table" then
    remote_items = (sd.remote_items == true) or (tonumber(sd.remote_items) == 1)
  end
  load_locations(cfg.locations)
  local n = 0
  for _ in pairs(LOC_MAIN) do n = n + 1 end
  for _ in pairs(LOC_SHOP) do n = n + 1 end
  log(("ready (v%s): slot #%d, remote_items=%s, %d location flags")
      :format(WORLD_VERSION, slot_number, tostring(remote_items), n))
end

function M.poll()
  local new = {}
  if not ADDRESSES_VERIFIED then return new end
  if not rom_is_ap() then return new end
  if not in_gameplay() then return new end
  if not textbox_clear() then return new end       -- client skips checks mid-textbox
  refresh_flags()
  scan_into(new)
  return new
end

function M.is_goal_complete()
  if not ADDRESSES_VERIFIED or not rom_is_ap() then return false end
  local gc = read_u8(GAME_CLEAR_OFF)
  return gc ~= nil and bit_and(gc, 0x01) ~= 0
end

-- Queue-driven delivery, mirroring Client.py's receive loop. ITEMQUEUE_HIGH is the
-- count already handed to the game; when it trails the delivered stream and the
-- game is idle (no item in flight, not in a cutscene), push the next item to the
-- correct receive slot and bump the counter — the patched game consumes it.
function M.receive_item(item_id, meta)
  if type(meta) == "table" then
    items_received[#items_received + 1] = {
      item     = tonumber(item_id),
      index    = tonumber(meta.index),
      player   = tonumber(meta.player),
      flags    = tonumber(meta.flags),
      location = tonumber(meta.location or meta.locId),
    }
  else
    items_received[#items_received + 1] = { item = tonumber(item_id) }
  end

  if not ADDRESSES_VERIFIED or not rom_is_ap() or not in_gameplay() then return end

  -- Game-busy gates (Client.py): don't push while an item is mid-process or a
  -- cutscene is running.
  local pend_item    = read_u8(ITEM_RECEIVED)
  local pend_special = read_u8(SPECIAL_RECEIVED)
  local pend_money   = read_u8(MONEY_RECIVED)
  if (pend_item and pend_item ~= 0) or (pend_special and pend_special ~= 0)
     or (pend_money and pend_money ~= 0) then return end
  local cutscene = read_u8(CUR_SCENE_OFF)
  if cutscene and cutscene ~= 0 then return end

  local list = delivery_list()
  local count = read_u16(ITEMQUEUE_HIGH)
  if count == nil then return end
  if count >= #list then return end

  local nxt = list[count + 1]
  if not (nxt and nxt.item) then return end
  local gid = nxt.item - ITEM_ID_BASE             -- game-local id (item-0xEB0000)

  -- advance the counter first (matches the client: it writes recv_index+1 before
  -- the item byte so a mid-frame re-entry doesn't double-deliver).
  write_u16(ITEMQUEUE_HIGH, count + 1)

  if gid <= 0xFD then
    write_u8(ITEM_RECEIVED, bit_and(gid, 0xFF))
  else
    local money_index = nil
    for i = 1, #MONEY_IDS do if MONEY_IDS[i] == gid then money_index = i end end
    if money_index ~= nil then
      write_u8(MONEY_RECIVED, money_index)          -- 1-based, == list index + 1
    else
      local special = CLIENT_SPECIALS[gid]
      if special ~= nil then
        write_u8(SPECIAL_RECEIVED, special)
      else
        -- Unknown high id: counter already advanced (so we don't wedge the queue);
        -- nothing safe to write. Logged for diagnosis.
        log(("skipped unmapped item id 0x%X (no money/special mapping)"):format(gid))
      end
    end
  end
end

return M
